@startuml
skinparam classBoxStyle {
    fillcolor: #f5f5f5
    borderStyle: solid
    borderColor: #cccccc
    shadow: true
}
skinparam classMemberStyle {
    style: circle
    color: #4CAF50
    label: "member"
}
skinparam classMemberStyle {
    style: square
    color: #F44336
    label: "attribute"
}
skinparam classMemberStyle {
    style: diamond
    color: #2196F3
    label: "operation"
}
skinparam classMemberStyle {
    style: diamond
    color: #2196F3
    label: "interface"
}

class Customer {
    +String name
    +List<Rental> rentals
    -Costumer(String name)
    -void addRental(Rental rental)
    -String getName()
    -String statement()
}

class Rental {
    +Movie movie
    +int daysRented
    -Rental(Movie movie, int daysRented)
    -int getDaysRented()
    -Movie getMovie()
    -double getCharge()
}

class Movie {
    static final int REGULAR = 0
    static final int NEW_RELEASE = 1
    static final int CHILDRENS = 2
    +String title
    +int priceCode
    -Movie(String title, int priceCode)
    -int getPriceCode()
    -void setPriceCode(int priceCode)
    -String getTitle()
}

Customer "1" -- "0" Rental : hasMany
Customer "1" -- "0" Movie : hasMany
@enduml
